# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler.cover_from_refinement_descent","kind":"function","src_hash":"8b07aaa54f2903ca","in":{"base":"RefinementDescent"},"out":{"base":"RefinementCover"},"spec":{"lhs":"cover_from_refinement_descent(rd)","rhs":"extract a refinementcover from a refinementdescent proof term","over":{"base":"RefinementDescent"},"name":"cover_from_refinement_descent_correct","kind":"composition"},"guarantee":"extract a refinementcover from a refinementdescent proof term","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"RefinementCover","by":"library_axiom"},{"fn":"tuple","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"47fede77a4ebb65b"}
def cover_from_refinement_descent(rd: RefinementDescent) -> RefinementCover:
    """Extract a RefinementCover from a RefinementDescent proof term."""
    fibers = []
    for name, pred_str in rd.fiber_predicates.items():
        sort = rd.var_sorts.get(rd.bound_var, 'Int')
        fibers.append(RefinementFiber(
            name=name, predicate=pred_str,
            bound_var=rd.bound_var, sort=sort,
        ))
    return RefinementCover(fibers=tuple(fibers))


