def check_seam(p_rhs: OTerm, q_lhs: OTerm) -> bool:
    """Check the composition seam: ∂¹(p) ≡ ∂⁰(q) definitionally."""
    return normalize(p_rhs).canon() == normalize(q_lhs).canon()


