    def check_unsat(self, formula: Any) -> bool:
        """Check formula is unsatisfiable."""
        if not _HAS_Z3:
            return False
        s = Solver()
        s.set('timeout', self._solver_timeout_ms)
        s.add(formula)
        return s.check() == unsat


