# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler._extract_branches","kind":"function","src_hash":"5d11efcef7d05756","in":{"base":"python_ast.AST","pred":"isinstance(node, python_ast.If)"},"out":{"base":"Set[str]"},"spec":{"lhs":"_extract_branches(fun)","rhs":"extract branch condition strings from a function ast","over":{"base":"python_ast.AST","pred":"isinstance(node, python_ast.If)"},"name":"_extract_branches_correct"},"guarantee":"extract branch condition strings from a function ast","fibers":[{"name":"python_ast_If","pred":"isinstance(node, python_ast.If)","path":{"lhs":"_extract_branches(x)","rhs":"extract branch condition strings from a function ast","over":{"base":"python_ast.If","pred":"isinstance(node, python_ast.If)"},"name":"_extract_branches_python_ast.If_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.c4_compiler._extract_branches_python_ast.If_correct","statement":"_extract_branches satisfies spec on python_ast.If inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"ddaa2a1996d7d4b7"}
def _extract_branches(func_def: python_ast.AST) -> Set[str]:
    """Extract branch condition strings from a function AST."""
    branches: Set[str] = set()
    for node in python_ast.walk(func_def):
        if isinstance(node, python_ast.If):
            try:
                cond_src = python_ast.unparse(node.test)
                branches.add(cond_src)
            except Exception:
                pass
    return branches


# ═══════════════════════════════════════════════════════════════════
# §9  PROOF COMPILATION — THE CORE
#
# Each ProofTerm subclass maps to a set of VCs via a unified
# cubical filling mechanism.
#
# The key unification: DESCENT = HCOMP.
# Both fill a cube from compatible face data.
# - Descent faces = refinement fibers
# - HComp faces = cubical faces
# - Face compatibility = overlap agreement = edge matching
# - Coverage = exhaustiveness = boundary completeness
#
# The compiler generates VCs for:
# 1. Face validity: each face proof compiles correctly
# 2. Edge agreement: adjacent faces agree on shared edges
# 3. Coverage: faces span the boundary
# Then fills the cube (produces global proof).
# ═══════════════════════════════════════════════════════════════════

