# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler._compile_cong","kind":"function","src_hash":"b2e208775079476a","in":{"base":"Cong"},"out":{"base":"C4Verdict"},"spec":{"lhs":"_compile_cong(pro)","rhs":"cong: congruence","over":{"base":"Cong"},"name":"_compile_cong_correct"},"guarantee":"cong: congruence","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.c4_compiler._compile_cong_correct","statement":"Path(_compile_cong(x), cong: congruence)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"24561b463b0a2eea"}
def _compile_cong(proof: Cong, lhs: OTerm, rhs: OTerm,
                  env: Z3Env, depth: int) -> C4Verdict:
    """Cong: congruence.  p : a = b ⊢ cong(f, p) : f(a) = f(b).

    Cubical: cong(f, p)(i) = f(p(i)).  The function f is applied
    uniformly along the path.
    """
    inner = compile_proof(proof.proof, lhs, rhs, env, depth + 1)
    vc = VC(rule='Cong', description=f'congruence under {proof.func_name}',
            formula=None, status=VCStatus.VERIFIED,
            detail=f'f={proof.func_name} applied to inner path')
    return C4Verdict(
        valid=inner.valid, trust=inner.trust,
        vcs=inner.vcs + [vc], errors=inner.errors)


