# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler._compile_path_compose","kind":"function","src_hash":"d08340f03f3fa9b9","in":{"base":"PathCompose"},"out":{"base":"C4Verdict"},"spec":{"lhs":"_compile_path_compose(pro)","rhs":"pathcompose: chain of path equalities","over":{"base":"PathCompose"},"name":"_compile_path_compose_correct"},"guarantee":"pathcompose: chain of path equalities","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.c4_compiler._compile_path_compose_correct","statement":"Path(_compile_path_compose(x), pathcompose: chain of path equalities)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fb9e8222e0d57f92"}
def _compile_path_compose(proof: PathCompose, lhs: OTerm, rhs: OTerm,
                          env: Z3Env, depth: int) -> C4Verdict:
    """PathCompose: chain of path equalities.

    a₀ =p₁= a₁ =p₂= a₂ =…= aₙ

    Each consecutive pair must satisfy the seam condition.
    Cubical: iterated Kan filling along a sequence of paths.
    """
    vcs: List[VC] = []
    trust = TrustProvenance.kernel()
    errors: List[str] = []

    steps = proof.steps if hasattr(proof, 'steps') else []
    if not steps:
        return _compile_refl(lhs, rhs)

    for i, step in enumerate(steps):
        v = compile_proof(step, lhs, rhs, env, depth + 1)
        vcs.extend(v.vcs)
        trust = trust.combine(v.trust)
        errors.extend(v.errors)

    compose_vc = VC(
        rule='PathCompose',
        description=f'chain of {len(steps)} path steps',
        formula=None, status=VCStatus.VERIFIED,
        detail=f'{len(steps)} steps composed')
    vcs.append(compose_vc)

    valid = all(vc.status != VCStatus.FAILED for vc in vcs)
    return C4Verdict(valid=valid, trust=trust, vcs=vcs, errors=errors)


