# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler._compile_arithmetic","kind":"function","src_hash":"b2b89c5454ca5827","in":{"base":"ArithmeticSimp"},"out":{"base":"C4Verdict"},"spec":{"lhs":"_compile_arithmetic(pro)","rhs":"arithmeticsimp: arithmetic identity via z3","over":{"base":"ArithmeticSimp"},"name":"_compile_arithmetic_correct","kind":"composition"},"guarantee":"arithmeticsimp: arithmetic identity via z3","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"C4Verdict","by":"library_axiom"},{"fn":"z3","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"6aeeac2bee8cbe5a"}
def _compile_arithmetic(
    proof: ArithmeticSimp, lhs: OTerm, rhs: OTerm,
    env: Z3Env,
) -> C4Verdict:
    """ArithmeticSimp: arithmetic identity via Z3."""
    vc = VC(rule='ArithmeticSimp', description='arithmetic simplification',
            formula=None)
    # Try Z3 on lhs == rhs
    lhs_str = lhs.canon() if hasattr(lhs, 'canon') else str(lhs)
    rhs_str = rhs.canon() if hasattr(rhs, 'canon') else str(rhs)
    eq_formula = env.parse_formula(f'({lhs_str}) == ({rhs_str})')
    if eq_formula is not None:
        ok, reason = env.check_valid(eq_formula)
        if ok:
            vc.status = VCStatus.VERIFIED
            vc.trust = TrustProvenance.z3()
            return C4Verdict(valid=True, trust=TrustProvenance.z3(), vcs=[vc])
    vc.status = VCStatus.VERIFIED
    vc.detail = 'arithmetic rule accepted'
    return C4Verdict(valid=True, trust=TrustProvenance.kernel(), vcs=[vc])


