# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler.ProductCover","kind":"class","src_hash":"e7b48ab14685a439","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"ProductCover(*args)","rhs":"correctly constructs a ProductCover instance","over":{"base":"Any"},"name":"ProductCover_class_invariant"},"guarantee":"correctly constructs a ProductCover instance","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"423ba512395b3c6c"}
class ProductCover:
    """Product of two refinement covers: U × V.

    Each fiber is (φᵢ ∧ ψⱼ).  The product cover is exhaustive iff
    both factors are exhaustive (Künneth).  Overlap structure is
    inherited: (i,j) overlaps (i',j') iff φᵢ∧φᵢ' is non-empty
    AND ψⱼ∧ψⱼ' is non-empty.
    """
    left: RefinementCover
    right: RefinementCover

    @property
# ╔══ CCTT ══════════════════════════════════════════════════╗
# ║ Path(fibers(), returns the fibers attribute) over Any      ║
# ╠════════════════════════════════════════════════════════════╣
# ║ fibers : Any → Tuple[RefinementFiber, ...]                 ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   lean.C4.Reduction.ReducesStar.refl                       ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | refl | Compiled: ✓ | 11869e6538f12db9           ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler.ProductCover.fibers","kind":"property","src_hash":"6c39a20898ad78d2","in":{"base":"Any"},"out":{"base":"Tuple[RefinementFiber, ...]"},"spec":{"lhs":"fibers()","rhs":"returns the fibers attribute","over":{"base":"Any"},"name":"fibers_correct"},"guarantee":"returns the fibers attribute","fibers":[],"h1":0,"paths":[],"strategy":"refl","details":{},"assumes":[],"trust":["lean.C4.Reduction.ReducesStar.refl"],"compiled":true,"vhash":"11869e6538f12db9"}
    def fibers(self) -> Tuple[RefinementFiber, ...]:
        """Generate product fibers: {φᵢ ∧ ψⱼ}."""
        result = []
        for fi in self.left.fibers:
            for fj in self.right.fibers:
                name = f'{fi.name}×{fj.name}'
                # Combine predicates with conjunction
                pred = f'({fi.predicate}) and ({fj.predicate})'
                # Combine bound variables
                bv = fi.bound_var if fi.bound_var == fj.bound_var else f'{fi.bound_var}_{fj.bound_var}'
                result.append(RefinementFiber(
                    name=name, predicate=pred,
                    bound_var=bv, sort=fi.sort))
        return tuple(result)

