# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler._extract_counterexample","kind":"function","src_hash":"79666ba32cd45e87","in":{"base":"Optional[C4Verdict]"},"out":{"base":"Dict[str, int]"},"spec":{"lhs":"_extract_counterexample(ver)","rhs":"extract counterexample values from a failed verdict's vc details","over":{"base":"Optional[C4Verdict]"},"name":"_extract_counterexample_correct"},"guarantee":"extract counterexample values from a failed verdict's vc details","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.c4_compiler._extract_counterexample_correct","statement":"Path(_extract_counterexample(x), extract counterexample values from a failed verdict's vc details)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8c8edec3dc66894a"}
def _extract_counterexample(verdict: Optional[C4Verdict]) -> Dict[str, int]:
    """Extract counterexample values from a failed verdict's VC details."""
    if verdict is None:
        return {}
    for vc in verdict.vcs:
        if vc.status == VCStatus.FAILED and vc.detail:
            # Parse Z3 counterexample from detail string
            # Format: "invalid (counterexample: [x = 5, y = -3])"
            import re
            matches = re.findall(r'(\w+)\s*=\s*(-?\d+)', vc.detail)
            if matches:
                return {name: int(val) for name, val in matches}
    return {}


# ── Synergy 7: Incremental verdict caching ───────────────────────
#
# Cache verdicts at fiber granularity: (predicate_hash, proof_hash) → verdict.
# When code changes in one branch, only that fiber is re-verified.
# The cache respects the cohomological structure:
#   - changing fiber i invalidates i and all overlaps involving i
#   - changing the cover itself invalidates exhaustiveness
#   - unchanged fibers keep their cached verdicts


