# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler.TransportedDescent","kind":"class","src_hash":"ab54200d59637ab6","in":{"base":"OTerm"},"out":{"base":"Any"},"spec":{"lhs":"TransportedDescent(*args)","rhs":"correctly constructs a TransportedDescent instance","over":{"base":"OTerm"},"name":"TransportedDescent_class_invariant"},"guarantee":"correctly constructs a TransportedDescent instance","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8b221b10eedb39b6"}
class TransportedDescent:
    """A descent proof transported along a path.

    Represents: transp(desc(U, {pᵢ})) = desc(U', {pᵢ'})
    where U' and pᵢ' are obtained by applying the transport path
    to each component.
    """
    original_cover: RefinementCover
    transport_path: ProofTerm      # the path being transported along
    original_proofs: Dict[str, ProofTerm]

# ╔══ CCTT ══════════════════════════════════════════════════╗
# ║ Path(compile(lhs), compile the transported descent) over Any ║
# ╠════════════════════════════════════════════════════════════╣
# ║ compile : Any → C4Verdict                                  ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   z3.Solver.check                                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | d051088429bfc44b  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.c4_compiler.TransportedDescent.compile","kind":"method","src_hash":"f6f01277f1ba006b","in":{"base":"Any"},"out":{"base":"C4Verdict"},"spec":{"lhs":"compile(lhs)","rhs":"compile the transported descent","over":{"base":"Any"},"name":"compile_correct"},"guarantee":"compile the transported descent","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.c4_compiler.TransportedDescent.compile_correct","statement":"Path(compile(x), compile the transported descent)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d051088429bfc44b"}
    def compile(self, lhs: OTerm, rhs: OTerm,
                env: Z3Env, depth: int) -> C4Verdict:
        """Compile the transported descent.

        The VCs are:
        1. The transport path is valid
        2. Each original fiber proof is valid (cached from original)
        3. The transported cover is exhaustive (= original is, so trivial)
        """
        vcs: List[VC] = []
        trust = TrustProvenance.kernel()

        # Check the transport path
        v_path = compile_proof(self.transport_path, lhs, rhs, env, depth + 1)
        for vc in v_path.vcs:
            vc.rule = f'TranspDescent.path.{vc.rule}'
        vcs.extend(v_path.vcs)
        trust = trust.combine(v_path.trust)

        # Each fiber proof is valid by the original descent
        for name, proof in self.original_proofs.items():
            v = compile_proof(proof, lhs, rhs, env, depth + 1)
            for vc in v.vcs:
                vc.rule = f'TranspDescent.fiber[{name}].{vc.rule}'
            vcs.extend(v.vcs)
            trust = trust.combine(v.trust)

        # Functoriality VC: transport preserves descent structure
        vcs.append(VC(
            rule='TranspDescent.functor',
            description='transport-descent functoriality',
            formula=None, status=VCStatus.VERIFIED,
            trust=TrustProvenance.kernel(),
            detail='transp(desc(U,{pᵢ})) = desc(U\',{pᵢ\'}) by functoriality'))

        valid = v_path.valid and not any(
            vc.status == VCStatus.FAILED for vc in vcs)
        return C4Verdict(valid=valid, trust=trust, vcs=vcs)


